// // This module inverts the behavior of the GPIO controller. When the enable signal is high, the output data retains its previous value. If the enable signal is low, the output data follows the input data.
module gpio_controller (  
    input wire clk,  
    input wire rst,  
    input wire enable,  
    input wire [7:0] data_in,  
    output reg [7:0] data_out  
);  
    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            data_out <= 8'b0;  
        end else if (enable) begin  
            data_out <= data_in;  
        end  
    end  
endmodule
